          <UIcon v-else-if="syncError" name="i-lucide-circle-alert" class="w-6 h-6 text-error" />
          <UIcon v-else name="i-lucide-circle-check" class="w-6 h-6 text-success" />
          <div>
            <div class="font-medium">
