async function loadTranscript(sessionId?: number) {
  if (!sessionId) {
    transcriptRaw.value = null
    parsedTranscript.value = null
    return
  }
  transcriptLoading.value = true
  try {
    try {
      parsedTranscript.value = await sessionApi.getNormalizedTranscript(sessionId)
