export const loginSchema = v.object({
  username: v.pipe(
    v.string('Username must be a string'),
    v.minLength(3, 'Username must be at least 3 characters'),
    v.maxLength(20, 'Username must be at most 20 characters'),
  ),
  password: v.pipe(
    v.string('Password must be a string'),
    v.minLength(6, 'Password must be at least 6 characters'),
  ),
  remember: v.optional(v.boolean()),
})

export type LoginSchema = v.InferOutput<typeof loginSchema>

<script setup lang="ts">
import { loginSchema } from '../schemas/login.schema'
import type { LoginForm } from '../types/auth.form'
import { useAuth } from '../composables/useAuth'

const { login, loading } = useAuth()

const form = reactive<LoginForm>({
  username: '',
  password: '',
  remember: false,
})

const handleSubmit = async () => {
  try {
    // Validate form
    const validatedData = await loginSchema.parseAsync(form)
    
    // Login
    await login({
      username: validatedData.username,
      password: validatedData.password,
    })
  } catch (error) {
    console.error('Login failed:', error)
  }
}
</script>

